#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N; int M;
        scanf("%lld %d", &N, &M);
        int single = 0;
        for (int i = 0; i < M; ++i) {
            int x; scanf("%d", &x);
            if (x == 1) ++single;
        }
        if (M == 1) {
            printf("0\n");
        } else {
            int need = (M - 1) - single;
            if (need < 0) need = 0;
            printf("%d\n", need);
        }
    }
    return 0;
}

