import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        M = int(next(it))
        single = 0
        for _ in range(M):
            if int(next(it)) == 1:
                single += 1
        if M == 1:
            out.append('0')
        else:
            need = (M - 1) - single
            if need < 0:
                need = 0
            out.append(str(need))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

